// v2.1: Fixed funding extraction - $5B cap, contextual matching, ignore PE fund sizes
const br = $json; const cd = $('Prep').item.json;

// Expanded PE/Growth Equity firm list (v2)
const peFirms = [
  'Vista Equity', 'Thoma Bravo', 'KKR', 'Blackstone', 'Bain Capital',
  'Silver Lake', 'Apollo', 'Insight Partners', 'Clearlake', 'TA Associates',
  'Brighton Park Capital', 'General Atlantic', 'Warburg Pincus',
  'Francisco Partners', 'Summit Partners', 'Providence Equity',
  'Welsh Carson', 'TPG Capital', 'Hellman & Friedman', 'Advent International',
  'Permira', 'EQT Partners', 'Carlyle', 'SoftBank Vision Fund'
];

const sr = br?.web?.results || [];
const txt = sr.map(r => (r.title || '') + ' ' + (r.description || '')).join(' ');

// Helper functions
const parseFundingAmount = (amountStr, unitStr) => {
  const amount = parseFloat(amountStr);
  const unit = unitStr.toLowerCase();
  if (unit === 'billion' || unit === 'b') return amount * 1000000000;
  if (unit === 'million' || unit === 'm') return amount * 1000000;
  return amount;
};

const formatFunding = (numeric) => {
  if (numeric >= 1000000000) return '$' + (numeric / 1000000000).toFixed(1) + 'B';
  if (numeric >= 1000000) return '$' + (numeric / 1000000).toFixed(1) + 'M';
  return '$' + numeric;
};

const MAX_BELIEVABLE_FUNDING = 5000000000; // $5B cap

// Extract employee count
let emp = null;
const em = txt.match(/([\d,]+)\s*employees?/i);
if (em) emp = parseInt(em[1].replace(/,/g, ''));

// Extract funding stage
let stg = null;
if (/Series\s*D/i.test(txt)) stg = 'Series D';
else if (/Series\s*C/i.test(txt)) stg = 'Series C';
else if (/Series\s*B/i.test(txt)) stg = 'Series B';
else if (/Series\s*A/i.test(txt)) stg = 'Series A';
else if (/\bSeed\b/i.test(txt)) stg = 'Seed';

// v2.1: IMPROVED funding extraction with sanity checks
let fund = null;
let fundNum = null;
const fundingCandidates = [];

// Priority patterns - contextual matches
const contextualPatterns = [
  /(?:raised|secur(?:ed|es)|total funding of|funding of|announced)\s*\$([\d.]+)\s*(million|billion|M|B)/gi,
  /\$([\d.]+)\s*(million|billion|M|B)\s*(?:raised|funding|round|series)/gi,
  /series\s*[A-D]\s*(?:funding|round)?\s*(?:of)?\s*\$([\d.]+)\s*(million|billion|M|B)/gi
];

for (const pattern of contextualPatterns) {
  let match;
  while ((match = pattern.exec(txt)) !== null) {
    const numeric = parseFundingAmount(match[1], match[2]);
    if (numeric <= MAX_BELIEVABLE_FUNDING && numeric >= 100000) {
      fundingCandidates.push({ numeric, raw: formatFunding(numeric), priority: 1 });
    }
  }
}

// Fallback: Any dollar amount
if (fundingCandidates.length === 0) {
  const fallbackPattern = /\$([\d.]+)\s*(million|billion|M|B)/gi;
  let match;
  while ((match = fallbackPattern.exec(txt)) !== null) {
    const numeric = parseFundingAmount(match[1], match[2]);
    if (numeric <= MAX_BELIEVABLE_FUNDING && numeric >= 100000) {
      fundingCandidates.push({ numeric, raw: formatFunding(numeric), priority: 2 });
    }
  }
}

// Select best candidate
if (fundingCandidates.length > 0) {
  fundingCandidates.sort((a, b) => {
    if (a.priority !== b.priority) return a.priority - b.priority;
    return b.numeric - a.numeric;
  });
  const best = fundingCandidates[0];
  fundNum = best.numeric;
  fund = best.raw;
}

// Check PE backing
const isPE = peFirms.some(f => txt.toLowerCase().includes(f.toLowerCase()));

// Extract founded year
let yr = null;
const ym = txt.match(/(?:founded|since)\s*(?:in)?\s*(\d{4})/i);
if (ym) yr = parseInt(ym[1]);

// Check for acquisition
let isAcquired = false;
let acquiredBy = null;
const acqMatch = txt.match(/acquired\s+by\s+([A-Za-z0-9\s]+?)(?:\s+for|\s+in|\.|,)/i);
if (acqMatch) {
  isAcquired = true;
  acquiredBy = acqMatch[1].trim();
} else if (/\bacquired\b|\bacquisition\b/i.test(txt) && /\bby\b/i.test(txt)) {
  isAcquired = true;
}

return {
  json: {
    recordId: cd.recordId,
    company_name: cd.company_name,
    company_url: cd.company_url,
    description: cd.description,
    source: cd.source,
    funding_stage: stg,
    total_funding: fund,
    total_funding_num: fundNum,
    employee_count: emp,
    pe_backed: isPE,
    founded_year: yr,
    is_acquired: isAcquired,
    acquired_by: acquiredBy
  }
};

// v2.1: Aligned thresholds with 100-point model - >150 employees, >$75M funding
const c = $json;
const reasons = [];

// === HARD DISQUALIFICATION FILTERS ===

// 1. Employee count > 150
if (c.employee_count && c.employee_count > 150) {
  reasons.push(`>150 employees (${c.employee_count})`);
}

// 2. Total funding > $75M
if (c.total_funding_num && c.total_funding_num > 75000000) {
  reasons.push(`>$75M funding (${c.total_funding})`);
}

// 3. PE/Growth Equity backed
if (c.pe_backed) {
  reasons.push('PE/Growth Equity backed');
}

// 4. Acquired company
if (c.is_acquired) {
  const byText = c.acquired_by ? ` by ${c.acquired_by}` : '';
  reasons.push(`Acquired${byText}`);
}

// 5. Series D+ (too late stage)
if (c.funding_stage === 'Series D') {
  reasons.push('Late stage (Series D)');
}

// === RESULT ===
const isDisqualified = reasons.length > 0;

return {
  json: {
    ...c,
    is_disqualified: isDisqualified,
    disqualify_reasons: reasons.join('; '),
    disqualify_count: reasons.length
  }
};

// v2.1: Disqualified record - skip Claude, score = 0, status = Auto-Disqualified
const c = $json;

const fields = {
  'Status': 'Auto-Disqualified',
  'Next Steps': 'Skip',
  'Tide-Pool Score': 0,
  'Sector Match': 'unknown',
  'CS Hire Likelihood': 'none',
  'Product Type': '',
  'Summary': `Auto-disqualified: ${c.disqualify_reasons}`,
  'Disqualify Reasons': c.disqualify_reasons
};

// Still update enriched fields if available
if (c.funding_stage) fields['Stage'] = c.funding_stage;
if (c.total_funding) fields['Total Funding'] = c.total_funding;
if (c.employee_count) fields['Employee Count'] = c.employee_count;
if (c.pe_backed) fields['PE Backed'] = c.pe_backed;
if (c.founded_year) fields['Founded Year'] = c.founded_year;

return { json: { recordId: c.recordId, fields: fields } };

const c = $json;
const sys = 'You are a company evaluator. Return ONLY valid JSON, no other text. Score 0-10 each dimension (80 max): build_opportunity, company_stage, company_size, sector_fit, technical_complexity, customer_journey_scope. HARD CAPS (max 35): DTC/consumer, biotech/pharma, defense/govt, hardware, Series D+, 500+ employees, $500M+ funding. SOFT CAP (max 40): 10yr+ companies. BUCKETS: APPLY(50+), WATCH(35-49), PASS(<35). Large late-stage companies are MAINTAINER roles not BUILDER opportunities - score build_opportunity 2-3 max. Output format: {"bucket":"APPLY|WATCH|PASS","total_score":N,"sector_match":"target|adjacent|unrelated","cs_hire_likelihood":"high|medium|low|unlikely","product_type":"enterprise|mid-market|self-serve|consumer","summary":"1 sentence"}';
const usr = 'Company: '+c.company_name+', URL: '+c.company_url+', Desc: '+(c.description||'').substring(0,150)+', Stage: '+(c.funding_stage||'?')+', Funding: '+(c.total_funding||'?')+', Emp: '+(c.employee_count||'?')+', Founded: '+(c.founded_year||'?');
return { json: { ...c, _sys: sys, _usr: usr } };

// v2.1: Clear Disqualify Reasons when record passes gates
const r = $json; const cd = $('Prompt').item.json;
let ev = {}; try { const t = r.content?.[0]?.text||''; const m = t.match(/\{[\s\S]*\}/); if(m) ev = JSON.parse(m[0]); } catch(e) { ev = {bucket:'WATCH',total_score:0,summary:'Parse error'}; }
if(!ev.total_score || ev.total_score < 1) { ev = {bucket:'WATCH',total_score:1,summary:'API error - retry'}; }
const sm = {'APPLY':'Apply','WATCH':'Monitor','PASS':'Skip'};
const nm = {'APPLY':'Apply Now','WATCH':'Watch for Jobs','PASS':'Skip'};
const fields = { 'Status':sm[ev.bucket]||'Research', 'Next Steps':nm[ev.bucket]||'Research', 'Tide-Pool Score':ev.total_score||1, 'Sector Match':ev.sector_match||'unknown', 'CS Hire Likelihood':ev.cs_hire_likelihood||'', 'Product Type':ev.product_type||'', 'Summary':ev.summary||'', 'Disqualify Reasons':'' };
if(cd.funding_stage) fields['Stage'] = cd.funding_stage;
if(cd.total_funding) fields['Total Funding'] = cd.total_funding;
if(cd.employee_count) fields['Employee Count'] = cd.employee_count;
if(cd.pe_backed) fields['PE Backed'] = cd.pe_backed;
if(cd.founded_year) fields['Founded Year'] = cd.founded_year;
return { json: { recordId:cd.recordId, fields:fields } };
